};

const SCENES = {
    alba:     { brightness: 70,  ct: 3200 },
    relax:    { brightness: 40,  ct: 2700 },
    focus:    { brightness: 80,  ct: 5000 },
    sera:     { brightness: 30,  ct: 2400 },
    notte:    { brightness: 10,  ct: 2000 },
    festa:    { brightness: 100, color: '0,100,100' },
    tempesta: { brightness: 50,  color: '240,60,55' },
    natura:   { brightness: 65,  color: '115,70,65' },
};

const COLORS = {
    rosso:   '0,100,70',
    verde:   '115,80,65',
    blu:     '240,100,60',
    giallo:  '50,100,80',
    arancio: '30,100,75',
    viola:   '290,80,65',
    rosa:    '340,60,80',
    bianco:  '0,0,100',
};

const action = msg.gaiaAction || {};
const stanza = (action.stanza || 'soggiorno').toLowerCase().trim();
const prefix = ROOM_MAP[stanza] || 'Soggiorno';
const caps = CAPS[prefix] || [];

if (action.power !== undefined) {
    if (caps.includes('power')) cmd(`${prefix}_Potenza`, action.power ? 'ON' : 'OFF');
    if (!action.power) return null;
}

if (action.brightness !== undefined) {
    if (caps.includes('power')) cmd(`${prefix}_Potenza`, 'ON');
    if (caps.includes('brightness')) cmd(`${prefix}_Luminosita`, Math.max(0, Math.min(100, Math.round(action.brightness))));
}

if (action.colore) {
    const c = action.colore.toLowerCase();
    if (c === 'warm') {
        if (caps.includes('power')) cmd(`${prefix}_Potenza`, 'ON');
        if (caps.includes('ct')) cmd(`${prefix}_Color_Temperature`, kelvinToPct(2700));
    } else if (c === 'cool') {
        if (caps.includes('power')) cmd(`${prefix}_Potenza`, 'ON');
        if (caps.includes('ct')) cmd(`${prefix}_Color_Temperature`, kelvinToPct(5000));
    } else {
        const hsb = COLORS[c] || c;
        if (caps.includes('power')) cmd(`${prefix}_Potenza`, 'ON');
        if (caps.includes('color')) cmd(`${prefix}_Colore`, hsb);
    }
}

if (action.color_temp) {
    if (caps.includes('power')) cmd(`${prefix}_Potenza`, 'ON');
    if (caps.includes('ct')) cmd(`${prefix}_Color_Temperature`, kelvinToPct(action.color_temp));
}

if (action.scena) {
    const scene = SCENES[action.scena.toLowerCase()];
    if (scene) {
        if (caps.includes('power')) cmd(`${prefix}_Potenza`, 'ON');
        if (caps.includes('brightness')) cmd(`${prefix}_Luminosita`, scene.brightness);
        if (scene.ct && caps.includes('ct')) cmd(`${prefix}_Color_Temperature`, kelvinToPct(scene.ct));
        if (scene.color && caps.includes('color')) cmd(`${prefix}_Colore`, scene.color);
    }
}

return null;

