// molto piu' spesso di quanto OpenHAB debba/possa incassare
const now = Date.now();
const lastSent = global.get('tdLightingLastSent') || {};
const key = `${item}_${field}`;
if (now - (lastSent[key] || 0) < 200) return null;
lastSent[key] = now;
global.set('tdLightingLastSent', lastSent);

let payload = msg.payload;
if (typeof payload === 'object') payload = JSON.stringify(payload);
return {
    url: `http://localhost:8080/rest/items/${item}_${field}`, method: 'POST',
    headers: { 'Content-Type': 'text/plain' }, payload: String(payload)
};

// GET /gaia/room-guess?room=<chiave_stanza_attuale>
// Non assegna nulla — suggerisce solo la stanza piu' probabile in base agli
// oggetti YOLO visti da quella telecamera, stesse firme del Device Registry
// (yoloVerify) ma usate per indovinare invece che per verificare una claim.
const brain = global.get('gaiaBrain') || {};
const room = (msg.req.query.room || '').trim();

const ROOM_SIGNATURES = {
    salotto:   ['couch', 'tv', 'chair', 'potted plant', 'remote'],
    sala:      ['dining table', 'chair', 'cup', 'bowl'],
    cucina:    ['refrigerator', 'bowl', 'cup', 'bottle', 'microwave', 'oven'],
    camera:    ['bed', 'person'],
    bagno:     ['toilet', 'sink', 'toothbrush'],
    studio:    ['laptop', 'keyboard', 'monitor', 'chair', 'book'],
    ingresso:  ['person', 'chair', 'backpack', 'handbag', 'umbrella'],
    garage:    ['car', 'bicycle', 'motorcycle'],
    giardino:  ['bicycle', 'dog', 'cat', 'potted plant'],
};

if (!room) {
    msg.statusCode = 400;
    msg.payload = { ok: false, error: 'query param "room" obbligatorio (chiave stanza attuale in brain.rooms)' };
    return msg;
}

const roomData = (brain.rooms || {})[room];
const objects = roomData?.objects || {};
const detectedObjs = Object.keys(objects).map(k => k.toLowerCase());

if (detectedObjs.length === 0) {
    msg.statusCode = 200;
    msg.payload = { ok: true, room, candidates: [], best: null,
                    message: 'Nessun oggetto rilevato ancora da questa telecamera' };
    return msg;
}

const candidates = Object.entries(ROOM_SIGNATURES).map(([candidateRoom, sig]) => {
    const matches = sig.filter(s => detectedObjs.some(d => d.includes(s)));
    const score = Math.round((matches.length / sig.length) * 100);
    return { room: candidateRoom, score, matched_objects: matches };
}).sort((a, b) => b.score - a.score);

msg.statusCode = 200;
msg.payload = {
    ok: true,
    room,
    detected_objects: detectedObjs,
    candidates,
    best: candidates[0]?.score > 0 ? candidates[0] : null,
};
return msg;
